var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"흥!","JPN":"フンッ！","ENG":"Hah!","TWN":"哼！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"제법 흥미로운 녀석이라고 생각했는데......","JPN":"結構興味深い奴だと思ったが……","ENG":"For a moment, I thought you were interesting.","TWN":"本以為是個有趣的傢伙……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그냥 완전히 맛이 가버린 인공지능이로군.","JPN":"こりゃあ、ただのとんだ勘違い野郎だな。","ENG":"But you're just completely delusional.","TWN":"看樣子只是一個功能錯亂的人工智慧而已。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"기계 주제에 무슨 가족 타령이야?","JPN":"機械のくせに家族がどうのこうのって話にならねえ。","ENG":"Machines don't have families.","TWN":"你一個機器還談什麼家人？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"됐어! 인격 데이터 따위는 모조리 지우고 분해해서 내 <color=#ffd34c>작품</color>의 부속품으로 써주마!","JPN":"よし、決めた！　人格データなんか全部削除して\\n分解して、俺の<color=#ffd34c>コレクション</color>のパーツにしてやる！","ENG":"Forget it! I'm just going to erase your personality data and disassemble you, so I can create a <color=#ffd34c>piece</color> of my own with your parts!","TWN":"算了！我要抹除你的人格資料，把你全部分解後用於我的<color=#ffd34c>作品</color>的零件！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"뭐, 뭐냐? 갑자기 함선 벽이 폭발하다니!","JPN":"な、何だ？　いきなり艦船の壁が爆発したぞ！","ENG":"W-what was that? The wall exploded all of a sudden!","TWN":"怎、怎麼回事？為什麼艦船牆壁會突然爆炸！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"뚜, 뚫었어! 대장!","JPN":"と、突破できたよ！　隊長！","ENG":"I-it's open, Cap!","TWN":"炸、炸開了！隊長！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"안녕하세요 해적 여러분~","JPN":"こんにちは、海賊のみなさーん。","ENG":"Hello, pirates.","TWN":"各位海盜，你們好啊～"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여러분들의 꿈과 희망을 산산이 분쇄하러 온 믿음과 신뢰의 알트 소대 리더, 서윤입니다!","JPN":"皆さんの夢と希望を木っ端みじんにしにきた、安心と\\n信頼のアルト小隊、リーダーのシズカです！","ENG":"My name is Seo Yoon, well known for trust and credibility. I'm here to completely pulverize your hopes and dreams!","TWN":"我是來粉碎各位的夢想和希望的信任與信賴之阿爾特小隊隊長，徐芸！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"알트 소대!","JPN":"アルト小隊！","ENG":"The ALT Squad!","TWN":"阿爾特小隊！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"내 부하들이 밖에서 너흴 막고 있었을 텐데?!","JPN":"俺の部下が外にいたはずだが！？","ENG":"What happened to my men outside?","TWN":"我的部下應該在外面阻擊你們才對啊？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"헹! 그런 약골 따위 이 유진님 앞에선 모조리 추풍낙수 같은 거지!","JPN":"ふん！　あんな雑魚どもの相手なんて、このシロコ様に\\nかかれば昼前飯だぜ！","ENG":"Heh, I, Eujin, completely obliviated those weaklings of yours!","TWN":"哼！他們在我劉珍面前如秋風落水！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"추풍낙엽이야 멍청아. 그리고 분명 절반은 내가 처리했던 것 같은데?","JPN":"朝飯前でしょ、脳筋イノシシ。それに半分は私が\\nやっつけたんだけど。","ENG":"Obliterated, you idiot. Also, I took care of half of them.","TWN":"是秋風落葉，笨蛋。而且有一大半是我處理的吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그, 그럴수가......","JPN":"そ、そんなはずは……","ENG":"N-no way...","TWN":"怎、怎麼可能……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"그 병력들을 겨우 너희 넷이서 처리했다고?","JPN":"あの人数を、たったの4人で始末しただと？","ENG":"There are only four of you. You took care of them all?","TWN":"你們四個人就打敗了那麼多兵力？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 네가 그 꼬마로구나, 우리 회사의 잠정적 미래 후계자!","JPN":"あ、あなたが例のおチビちゃんね？　我が社の\\n暫定後継者！","ENG":"Oh, you're that girl, the potential successor of our company, right?","TWN":"啊，你就是那個小孩吧，我們公司未來的繼承者！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응? 언니들은 누구야?","JPN":"む？　お姉ちゃんたちは誰？","ENG":"Hm? Who are you?","TWN":"嗯？姐姐們是誰？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이제 안심해. 널 위해 사장님께서 우릴 보내셨거든.","JPN":"もう大丈夫よ。あなたを助けるために社長が私たちを\\nここに派遣したの。","ENG":"You're safe now. Boss sent us to save you.","TWN":"放心，是老闆派我們來救你的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 정말? 아빠가 날 구하라고 했어?","JPN":"え！　本当に？　パパが私のことを助けるように\\n言ったの？","ENG":"Oh, really? Did Daddy send you to save me?","TWN":"啊！真的嗎？是爸爸讓你們來救我的？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼~ 못 믿겠으면 이걸 받으렴.","JPN":"もちろんよ～。信じられないなら、これを受け取って。","ENG":"Of course. Here, take this.","TWN":"當然～不信就看看這個。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이건......?","JPN":"これは……？","ENG":"This is...","TWN":"這個……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사장님께서 너에게 전해주라고 한 호출기야.","JPN":"社長があなたに渡すようにって。呼び出し機よ。","ENG":"Boss asked me to give you that beeper.","TWN":"是老闆讓我交給你的呼叫機。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이것만 있으면 언제 어디서라도 사장님께서 직접 구해주러 올 거라고 하셨어.","JPN":"これで呼べば、いつでもどこでも社長が自ら助けに来るそうよ。","ENG":"Whenever you use it, from wherever you are, Boss will come to save you.","TWN":"有了這個，不管你在哪裡，老闆都可以親自來救你。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"사용법은 전해주면 알 거라고 하시던데?","JPN":"使い方は本人の手に渡ればわかるだろうって言ってたよ？","ENG":"He also said that you know how to use it.","TWN":"他說你應該知道使用方法。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"정말이네...... 이 물건에서 아빠의 기운이 느껴져.","JPN":"ホントだ……この機械、パパの気配がする。","ENG":"You're right. I can feel his energy from this thing.","TWN":"確實……我感受到了爸爸的氣息。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"테라브레인 서브 모듈 인식.","JPN":"テラブレイン、サブモジュールを認識。","ENG":"Recognizing Terrabrain submodule...","TWN":"特拉大腦輔助模組識別。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"동기화 성공. 에너지 충전 완료.","JPN":"同期に成功。エネルギーチャージ完了。","ENG":"Synchronized. Energy charging completed.","TWN":"同步成功，充能完畢。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"호출 코드 입력을 기다리고 있습니다.","JPN":"呼び出しコードを入力してください。","ENG":"Waiting for you to enter summon code.","TWN":"等待輸入呼叫代碼。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_76"},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"흐읍......!","JPN":"ふうっ……！","ENG":"*Takes a deep breath*","TWN":"唔……！"},"stage":{"bg":"BLACK","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......아빠! 도와줘!!","JPN":"……パパ！　助けて！！","ENG":"Daddy! Help!","TWN":"……爸爸！救我！！"},"stage":{"bg":"BLACK","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"내가 왔다!","JPN":"来たぞ！","ENG":"Here I come!","TWN":"我來了！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GAP_SILVER_NULL_NULL","text":{"KOREA":"감히 누가 우리 딸, 기를 죽이고 그러지? 네놈인가?!","JPN":"誰がうちの愛娘をいじめたんだ？　貴様か！？","ENG":"Who's bullying my lovely daughter? Is that you?","TWN":"誰敢欺負我的女兒？是你嗎？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_SILVER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"저, 저 로봇은 또 뭐야!!","JPN":"あ、あのロボットはまた何だ！！","ENG":"W-where did that robot come from?","TWN":"那、那個機器人又是什麼！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"이놈이고 저놈이고! 이게 무슨 소꿉놀이라도 되는 줄 아는 건가?","JPN":"どいつもこいつも！　おままごとでもしてるつもりか？","ENG":"All of you, do you think this is child's play?","TWN":"你們一個個！以為是扮家家酒嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"네놈들을 전부 이곳에서 끝을 내주마!","JPN":"貴様ら全員、ここで仕留めてやる！","ENG":"I'm going to end you all, right here and now!","TWN":"我要在這裡把你們全部殺掉！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SIGMA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};